public class Student {
    String name;
    int age;
    double gpa;

    // No-arg constructor (like the default, but with explicit defaults)
    public Student() {
        this.name = "Unknown";
        this.age = 0;
        this.gpa = 0.0;
    }

    // Parameterized constructor
    public Student(String name, int age, double gpa) {
        this.name = name;
        this.age = age;
        this.gpa = gpa;
    }

    public void display() {
        System.out.println("Name: " + name + ", Age: " + age + ", GPA: " + gpa);
    }

    public static void main(String[] args) {
        Student s1 = new Student();                         // calls no-arg
        Student s2 = new Student("Alice", 20, 3.85);       // calls parameterized
        Student s3 = new Student("Bob", 22, 3.50);

        s1.display();
        s2.display();
        s3.display();
    }
}

public class Product {
    private String name;
    private double price;
    private String category;
    private int stock;

    // Most complete constructor
    public Product(String name, double price, String category, int stock) {
        this.name = name;
        this.price = price;
        this.category = category;
        this.stock = stock;
        System.out.println("Full constructor called for: " + name);
    }

    // 3-param constructor chains to 4-param with default stock
    public Product(String name, double price, String category) {
        this(name, price, category, 100); // default stock = 100
        System.out.println("3-param constructor done");
    }

    // 2-param constructor chains to 3-param with default category
    public Product(String name, double price) {
        this(name, price, "General"); // default category
        System.out.println("2-param constructor done");
    }

    @Override
    public String toString() {
        return String.format("Product{name='%s', price=%.2f, category='%s', stock=%d}",
            name, price, category, stock);
    }

    public static void main(String[] args) {
        System.out.println("--- Creating p1 ---");
        Product p1 = new Product("Laptop", 999.99, "Electronics", 50);
        System.out.println(p1);

        System.out.println("\n--- Creating p2 ---");
        Product p2 = new Product("Headphones", 79.99, "Audio");
        System.out.println(p2);

        System.out.println("\n--- Creating p3 ---");
        Product p3 = new Product("USB Cable", 9.99);
        System.out.println(p3);
    }
}

public class Vehicle {
    protected String brand;
    protected int year;
    protected double price;

    public Vehicle(String brand, int year, double price) {
        this.brand = brand;
        this.year = year;
        this.price = price;
    }

    public String getInfo() {
        return brand + " (" + year + ") - $" + price;
    }
}

class ElectricCar extends Vehicle {
    private int batteryCapacity; // in kWh
    private int range;           // in km

    // Subclass constructor calls super() for parent fields
    public ElectricCar(String brand, int year, double price, int batteryCapacity, int range) {
        super(brand, year, price); // MUST be first statement
        this.batteryCapacity = batteryCapacity;
        this.range = range;
    }

    // Copy constructor — creates a deep copy of another ElectricCar
    public ElectricCar(ElectricCar other) {
        super(other.brand, other.year, other.price);
        this.batteryCapacity = other.batteryCapacity;
        this.range = other.range;
    }

    @Override
    public String getInfo() {
        return super.getInfo() + " | Battery: " + batteryCapacity + "kWh | Range: " + range + "km";
    }

    public static void main(String[] args) {
        ElectricCar car1 = new ElectricCar("Tesla", 2024, 45000, 100, 600);
        ElectricCar car2 = new ElectricCar(car1); // copy constructor

        System.out.println("Original: " + car1.getInfo());
        System.out.println("Copy:     " + car2.getInfo());

        // Verify independence — modifying copy doesn't affect original
        car2.brand = "Tesla Copy";
        System.out.println();
        System.out.println("After modifying copy:");
        System.out.println("Original: " + car1.getInfo());
        System.out.println("Copy:     " + car2.getInfo());
    }
}

// Singleton Pattern — private constructor
class DatabaseConnection {
    private static DatabaseConnection instance;
    private final String url;
    private final int port;
    private boolean connected;

    private DatabaseConnection(String url, int port) {
        this.url = url;
        this.port = port;
        this.connected = false;
        System.out.println("Connecting to " + url + ":" + port);
        this.connected = true; // simulate connection
    }

    public static DatabaseConnection getInstance() {
        if (instance == null) {
            instance = new DatabaseConnection("prod-db.example.com", 5432);
        }
        return instance;
    }

    public String getStatus() {
        return url + ":" + port + " | connected=" + connected;
    }
}

// Builder Pattern — complex object construction
class HttpRequest {
    private final String url;
    private final String method;
    private final String body;
    private final int timeout;
    private final boolean followRedirects;

    private HttpRequest(Builder builder) {
        this.url = builder.url;
        this.method = builder.method;
        this.body = builder.body;
        this.timeout = builder.timeout;
        this.followRedirects = builder.followRedirects;
    }

    public static class Builder {
        private final String url;
        private String method = "GET";
        private String body = "";
        private int timeout = 30;
        private boolean followRedirects = true;

        public Builder(String url) { this.url = url; }
        public Builder method(String method) { this.method = method; return this; }
        public Builder body(String body) { this.body = body; return this; }
        public Builder timeout(int timeout) { this.timeout = timeout; return this; }
        public Builder followRedirects(boolean follow) { this.followRedirects = follow; return this; }
        public HttpRequest build() { return new HttpRequest(this); }
    }

    @Override
    public String toString() {
        return String.format("HttpRequest{url='%s', method='%s', timeout=%d, body='%s', redirect=%b}",
            url, method, timeout, body.isEmpty() ? "(none)" : body, followRedirects);
    }

    public static void main(String[] args) {
        // Singleton
        DatabaseConnection db1 = DatabaseConnection.getInstance();
        DatabaseConnection db2 = DatabaseConnection.getInstance(); // no new connection
        System.out.println("Same instance? " + (db1 == db2));
        System.out.println("Status: " + db1.getStatus());

        System.out.println();

        // Builder
        HttpRequest req1 = new HttpRequest.Builder("https://api.example.com/data")
            .method("POST")
            .body("{\"key\": \"value\"}")
            .timeout(60)
            .followRedirects(false)
            .build();

        HttpRequest req2 = new HttpRequest.Builder("https://api.example.com/users")
            .build(); // uses all defaults

        System.out.println(req1);
        System.out.println(req2);
    }
}

