import java.util.Arrays;

public class Student {
    private String name;
    private int[] grades;
    private int year;

    // Parameterized constructor
    public Student(String name, int[] grades, int year) {
        this.name = name;
        this.grades = Arrays.copyOf(grades, grades.length); // defensive copy
        this.year = year;
    }

    // Copy constructor (deep copy)
    public Student(Student other) {
        this.name = other.name;
        this.grades = Arrays.copyOf(other.grades, other.grades.length);
        this.year = other.year;
    }

    public double getGPA() {
        int sum = 0;
        for (int g : grades) sum += g;
        return (double) sum / grades.length;
    }

    public void setGrade(int index, int grade) {
        grades[index] = grade;
    }

    @Override
    public String toString() {
        return String.format("Student{name='%s', year=%d, GPA=%.2f}", name, year, getGPA());
    }

    public static void main(String[] args) {
        Student alice = new Student("Alice", new int[]{90, 85, 92, 88}, 2);
        Student alice2 = new Student(alice); // copy

        System.out.println("Original Alice GPA: " + alice.getGPA());
        alice2.setGrade(0, 70); // modify copy
        System.out.printf("Copy Alice2 GPA (after change): %.2f%n", alice2.getGPA());
        System.out.println("Original Alice GPA (unchanged): " + alice.getGPA());
    }
}

