public final class HttpConnection {
    private final String host;
    private final int port;
    private final String protocol;
    private final int timeout;
    private final int maxRetries;

    private HttpConnection(Builder builder) {
        this.host = builder.host;
        this.port = builder.port;
        this.protocol = builder.protocol;
        this.timeout = builder.timeout;
        this.maxRetries = builder.maxRetries;
    }

    @Override
    public String toString() {
        return String.format(
            "HttpConnection{host='%s', port=%d, protocol='%s', timeout=%d, maxRetries=%d}",
            host, port, protocol, timeout, maxRetries);
    }

    public static class Builder {
        private final String host; // required
        private int port = 80;
        private String protocol = "http";
        private int timeout = 30;
        private int maxRetries = 3;

        public Builder(String host) {
            if (host == null || host.trim().isEmpty())
                throw new IllegalArgumentException("Host cannot be empty");
            this.host = host;
        }

        public Builder port(int port) {
            if (port < 1 || port > 65535)
                throw new IllegalArgumentException("Port must be 1-65535");
            this.port = port; return this;
        }
        public Builder protocol(String protocol) { this.protocol = protocol; return this; }
        public Builder timeout(int timeout) {
            if (timeout <= 0) throw new IllegalArgumentException("Timeout must be positive");
            this.timeout = timeout; return this;
        }
        public Builder maxRetries(int maxRetries) { this.maxRetries = maxRetries; return this; }
        public HttpConnection build() { return new HttpConnection(this); }
    }

    public static void main(String[] args) {
        HttpConnection conn1 = new Builder("api.example.com")
            .port(443).protocol("https").timeout(60).maxRetries(5).build();
        HttpConnection conn2 = new Builder("localhost").build();
        HttpConnection conn3 = new Builder("db.server.com").port(5432).timeout(10).build();

        System.out.println("Connection 1: " + conn1);
        System.out.println("Connection 2: " + conn2);
        System.out.println("Connection 3: " + conn3);
    }
}
